import java.util.Scanner;

public class BufferOverflowExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Assume the input is limited to 10 characters
        char[] buffer = new char[10];

        // Copy user input into buffer without proper bounds checking
        for (int i = 0; i < name.length(); i++) {
            buffer[i] = name.charAt(i);
        }

        // Vulnerability: If the user inputs more than 10 characters, it will cause a buffer overflow
    }
}

